sql:
SELECT email
FROM users
WHERE id = 0 AND last_login < datetime('now', '-7 days');

SELECT user_id 
FROM group_memberships 
WHERE group_name = 'admin';

SELECT REPLACE(value, '-', '') AS phone_number
FROM user_metadata
WHERE user_id = 0 AND key = 'phone';

SELECT user_id 
FROM user_metadata 
WHERE metadata_id = 0;

external_knowledge:
- "break the digital fortress" refers to an unsuccessful login attempt (la.success = 0);
- "familiar yet foreign IP address 192.168.1.1" is a metaphor for a well-known IP address within a network, but not necessarily a trusted one in this context;
- "hanging in limbo" refers to a pending status in the password_resets table.

sql:
SELECT u.firstname, u.lastname
FROM users u
INNER JOIN group_memberships gm ON u.id = gm.user_id
WHERE gm.group_name = '0' AND u.id IN (
  SELECT user_id FROM user_metadata
);
